# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <vector>
#include <stdio.h>  // For file handling functions

class FileDescriptorPool {
    std::vector<int> fds;  // Vector to store the file descriptors

public:
    ~FileDescriptorPool() { cleanup(); }  // Clean up in destructor

    void add(const char* filename) {
        int fd = open(filename, O_RDWR);  // Open a new file for reading and writing
        if (fd != -1) {
            fds.push_back(fd);  // If successful, add the file descriptor to our pool
        } else {
            perror("Error opening file");
        }
    }

    void remove(int index) {
        if (index >= 0 && index < fds.size()) {
            close(fds[index]);  // If valid, close the file descriptor and remove it from our pool
            fds.erase(fds.begin() + index);
        } else {
            printf("Invalid file descriptor index.\n");
        }
    }

    void cleanup() {
        for (int fd : fds) {  // For every file descriptor in our pool
            close(fd);  // Close and free the associated resources
        }
        fds.clear();  // Clear the vector, freeing up its memory
    }
};